import React, { ReactElement, Fragment } from "react";

interface Props {
  projects: IProject[];
}

interface IProject {
  name: string;
  description: string;
  stack: string[];
  image: string;
  repo: string;
  site: string;
}

interface IProjectProps extends IProject {
  alt: boolean;
}

export default function Projects({ projects }: Props): ReactElement {
  console.log(projects);

  return (
    <Fragment>
      <div id="projects" className="projects">
        <h1>Projects</h1>
        {projects.map((project, i) => (
          <Project alt={i % 2 != 0} {...project} />
        ))}
      </div>
      <div className="projects-more"></div>
    </Fragment>
  );
}

function Project({
  alt,
  name,
  description,
  stack,
  image,
  repo,
  site,
}: IProjectProps): ReactElement {
  return (
    <div className={`project ${alt ? "alt" : ""}`}>
      <img className="image" src="/projects/typeracer.png" />
      <div className="content">
        <h2>
          {name}
          {/* <span>Ongoing</span> */}{" "}
        </h2>
        <div className="stack">
          {stack.map((tech) => (
            <img src={`/skills/${tech.toLowerCase()}.png`} alt={tech} />
          ))}
        </div>
        <p>{description}</p>
      </div>
      <div className="links">
        <a href={repo}>
          <i className="fas fa-code"></i>
        </a>
        <a>
          <i className="fas fa-eye"></i>
        </a>
      </div>
    </div>
  );
}
